class Solution {
public:
    int findUnsortedSubarray(vector<int>& nums) {
        int n = nums.size();
        int start = n, end = 0;
        for (int i = 1; i < n; ++i) {
            if (nums[i] < nums[i - 1]) {
                start = min(start, i);
                end = max(end, i);
            }
        }
        return end - start + 1;
    }
};
